package com.seaquake6324.civitas.domain.security;import static org.junit.jupiter.api.Assertions.*;import com.seaquake6324.civitas.domain.ChunkCoordinate;import java.util.*;import org.junit.jupiter.api.Test;
class SecurityTopologyTest{@Test void findsCardinalBorderDistance(){Set<Long>territory=new HashSet<>();for(int x=-2;x<=2;x++)for(int z=-2;z<=2;z++)territory.add(ChunkCoordinate.pack(x,z));assertEquals(2,SecurityTopology.borderDistance(territory,ChunkCoordinate.pack(0,0),64).distance());assertFalse(SecurityTopology.borderDistance(territory,ChunkCoordinate.pack(0,0),64).limited());}@Test void reportsBoundInsteadOfScanningUnboundedTerritory(){Set<Long>territory=new HashSet<>();for(int x=-10;x<=10;x++)for(int z=-10;z<=10;z++)territory.add(ChunkCoordinate.pack(x,z));assertTrue(SecurityTopology.borderDistance(territory,ChunkCoordinate.pack(0,0),4).limited());}}
